### Capture Trace on Playwright Global Setup Failure (TypeScript)

Source: https://github.com/microsoft/playwright/blob/main/docs/src/test-global-setup-teardown-js.md

This global setup script includes error handling to capture a trace of the execution context if an error occurs. It starts tracing before performing setup actions and stops tracing, saving the trace to a file, either on success or failure.

```typescript
import { chromium, type FullConfig } from '@playwright/test';

async function globalSetup(config: FullConfig) {
  const { baseURL, storageState } = config.projects[0].use;
  const browser = await chromium.launch();
  const context = await browser.newContext();
  const page = await context.newPage();
  try {
    await context.tracing.start({ screenshots: true, snapshots: true });
    await page.goto(baseURL!); // Assuming baseURL is defined in playwright.config.ts
    await page.getByLabel('User Name').fill('user');
    await page.getByLabel('Password').fill('password');
    await page.getByText('Sign in').click();
    await context.storageState({ path: storageState as string }); // Saves state to the specified path
    await context.tracing.stop({
      path: './test-results/setup-trace.zip',
    });
    await browser.close();
  } catch (error) {
    await context.tracing.stop({
      path: './test-results/failed-setup-trace.zip', // Path for failed trace
    });
    await browser.close();
    throw error; // Re-throw the error to indicate setup failure
  }
}

export default globalSetup;
```

