### Authenticate and Reuse State in Playwright Global Setup (TypeScript)

Source: https://github.com/microsoft/playwright/blob/main/docs/src/test-global-setup-teardown-js.md

This global setup script authenticates a user and saves the authentication state to a file, which can then be reused across tests. It requires Playwright's configuration to specify `baseURL` and `storageState`. The output is a `state.json` file.

```typescript
import { chromium, type FullConfig } from '@playwright/test';

async function globalSetup(config: FullConfig) {
  const { baseURL, storageState } = config.projects[0].use;
  const browser = await chromium.launch();
  const page = await browser.newPage();
  await page.goto(baseURL!); // Assuming baseURL is defined in playwright.config.ts
  await page.getByLabel('User Name').fill('user');
  await page.getByLabel('Password').fill('password');
  await page.getByText('Sign in').click();
  await page.context().storageState({ path: storageState as string }); // Saves state to the specified path
  await browser.close();
}

export default globalSetup;
```

